Code:
import java.util.ArrayList;

public int[] withoutTen(int[] nums) {
    ArrayList<Integer> list = new ArrayList<>();
    for (int num : nums) {
        if (num != 10) {
            list.add(num);
        }
    }
    int[] result = new int[nums.length];
    for (int i = 0; i < list.size(); i++) {
        result[i] = list.get(i);
    }
    return result;
}

